# Contradiction detection: before merging, check if cluster members contradict each other.
# If they do, flag for human review rather than auto-merging.

def detect_contradiction(texts: list[str]) -> bool:
    """
    Ask Haiku whether the given statements contradict each other.
    Returns True if a contradiction is detected.
    """
    combined = "\n".join(f"{i+1}. {t}" for i, t in enumerate(texts))
    resp = client_a.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=64,
        messages=[{"role": "user", "content": (
            "Do any of the following statements contradict each other? "
            "Reply ONLY with JSON: {\"contradiction\": true} or {\"contradiction\": false}\n\n"
            + combined[:1500]
        )}],
    )
    import json as _json
    try:
        return _json.loads(resp.content[0].text).get("contradiction", False)
    except Exception:
        return False   # on parse failure, allow merge

def safe_merge_cluster(
    collection: str,
    cluster_ids: list[str],
    dry_run: bool = False,
) -> str | None:
    """Merge only if no contradiction is detected among cluster members."""
    records = client_q.retrieve(
        collection_name=collection,
        ids=cluster_ids,
        with_payload=True,
    )
    texts = [r.payload.get("text", "") for r in records if r.payload.get("text")]
    if len(texts) < 2:
        return merge_cluster(collection, cluster_ids, dry_run=dry_run)

    if detect_contradiction(texts):
        # Flag for review — don't auto-merge
        for r in records:
            client_q.set_payload(
                collection_name=collection,
                payload={"needs_review": True, "contradiction_cluster": cluster_ids},
                points=[r.id],
            )
        return None

    return merge_cluster(collection, cluster_ids, dry_run=dry_run)
